-- Post-MVP-072 / Issue #194: split fishing range and hydrology details.
-- Forward-only expand/data migration. The legacy composite rows remain for audit and rollback; only its definition is made inactive.

insert into public.fishing_spot_detail_item_definitions (item_key, category, value_kind, label_ja, description, display_order, is_active) values
('fishable_area', 'access', 'text_list', '釣り可能範囲', '釣り可能と確認できた具体的な範囲。利用可否や規制情報とは分けて扱う。', 135, true),
('tidal_flow', 'hydrology', 'enum', '潮通し', '地点単位で確認した潮通し。', 140, true),
('river_influence', 'hydrology', 'enum', '河川影響', '地点単位で確認した河川の影響。', 150, true),
('open_sea_bay_character', 'hydrology', 'enum', '外海・湾内特性', '地点単位で確認した外海・湾内の特性。', 160, true)
on conflict (item_key) do update set category=excluded.category, value_kind=excluded.value_kind, label_ja=excluded.label_ja, description=excluded.description, display_order=excluded.display_order, is_active=true, updated_at=now();

