-city-gallery","ikitsuki-area-src-ikitsuki-area-statistics","ikitsuki-area-src-ikitsuki-area-org","ikitsuki-area-src-ikitsuki-area-gsi-map"],"contradicting":[]}}]}]}'::jsonb;
  spot jsonb; source jsonb; value jsonb; rel text; source_id_text text; detail_uuid uuid; source_uuid uuid;
begin
  for spot in select * from jsonb_array_elements(payload->'spots') loop
    for source in select * from jsonb_array_elements(spot->'sources') loop
      source_uuid := (substr(md5(source->>'id'),1,8)||'-'||substr(md5(source->>'id'),9,4)||'-'||substr(md5(source->>'id'),13,4)||'-'||substr(md5(source->>'id'),17,4)||'-'||substr(md5(source->>'id'),21,12))::uuid;
      insert into public.fishing_spot_detail_sources (id, source_type, source_name, source_url, checked_on, note) values
        (source_uuid, source->>'sourceType', source->>'sourceName', nullif(source->>'sourceUrl',''), nullif(source->>'checkedOn','')::date, source->>'note')
      on conflict (id) do update set source_type=excluded.source_type, source_name=excluded.source_name, source_url=excluded.source_url, checked_on=excluded.checked_on, note=excluded.note, updated_at=now();
    end loop;
    for value in select * from jsonb_array_elements(spot->'values') loop
      detail_uuid := (substr(md5(value->>'id'),1,8)||'-'||substr(md5(value->>'id'),9,4)||'-'||substr(md5(value->>'id'),13,4)||'-'||substr(md5(value->>'id'),17,4)||'-'||substr(md5(value->>'id'),21,12))::uuid;
      delete from public.fishing_spot_detail_value_sources where detail_value_id=detail_uuid;
      insert into public.fishing_spot_detail_values (id, spot_id, item_key, information_state, value_text, value_text_list, value_number, value_boolean, value_json, unit, confidence, contribution_origin, moderation_status, review_status, adoption_status, note, internal_note, checked_at) values
        (detail_uuid, spot->>'spotId', value->>'itemKey', value->>'informationState', nullif(value->>'valueText',''), coalesce(array(select jsonb_array_elements_text(value->'valueTextList')), '{}'::text[]), null, null, null, null, nullif(value->>'confidence',''), 'curated_research', 'not_required', 'reviewed', 'adopted', value->>'note', 'Issue #194 item-by-item reassessment; not derived from water_flow_influences', nullif(value->>'checkedAt','')::date)
      on conflict (id) do update set information_state=excluded.information_state, value_text=excluded.value_text, value_text_list=excluded.value_text_list, confidence=excluded.confidence, note=excluded.note, internal_note=excluded.internal_note, checked_at=excluded.checked_at, review_status='reviewed', adoption_status='adopted', updated_at=now();
      foreach rel in array array['supporting','checked','contradicting'] loop
        for source_id_text in select jsonb_array_elements_text(value->'sources'->rel) loop
          source_uuid := (substr(md5(source_id_text),1,8)||'-'||substr(md5(source_id_text),9,4)||'-'||substr(md5(source_id_text),13,4)||'-'||substr(md5(source_id_text),17,4)||'-'||substr(md5(source_id_text),21,12))::uuid;
          insert into public.fishing_spot_detail_value_sources (detail_value_id, source_id, relation) values (detail_uuid, source_uuid, rel) on conflict (detail_value_id, source_id) do update set relation=excluded.relation;
        end loop;
      end loop;
    end loop;
  end loop;
end $$;

